-- Migración para crear la tabla de ejercicios y sembrar los movimientos de CrossFit

-- 1. Crear la tabla de ejercicios
CREATE TABLE IF NOT EXISTS ejercicios (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    nombre TEXT NOT NULL UNIQUE,
    categoria TEXT NOT NULL,
    descripcion TEXT,
    equipamiento TEXT NOT NULL,
    url_video TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT timezone('utc'::text, now()) NOT NULL
);

-- 2. Habilitar RLS
ALTER TABLE ejercicios ENABLE ROW LEVEL SECURITY;

-- 3. Crear política permisiva para desarrollo rápido
CREATE POLICY "Permitir todo acceso público a ejercicios" ON ejercicios FOR ALL USING (true) WITH CHECK (true);

-- 4. Sembrado (seeder) de ejercicios clásicos de CrossFit
ON CONFLICT (nombre) DO NOTHING;
